var authGuard = (route) => {
  const service = inject2(AuthService);
  const router = inject2(Router);
  const urlToken = route.queryParamMap.get("token");
  if (urlToken) {
    return true;
  }
  if (service.isLoggedIn()) {
    return true;
  } else {
    router.navigate(["/auth"], {
      queryParams: { returnUrl: router.url }
    });
    return false;
  }
};

